/*欢迎使用同花顺公式系统*/
/*按“CTRL+S”启动AI，可输入需求描述生成相应代码*/
AT:=ZIG(3,5)+0.5,linethick2;
GT:=EMA(AT,2);
BT:=ZIG(3,10),linethick2;
HT:=EMA(BT,2);
DRAWTEXT((HT>BT),105,''),COLOR00FF00;
DRAWTEXT((BT>HT),5,''),colorred;
DRAWICON(CROSS(AT,GT),10,"BUY");
DRAWICON(CROSS(GT,AT),90,"SELL");
AA:=(O+H+L+C)/4;
BB:=MA(AA,3);
CC:=SUM(IF(AA>REF(AA,1),AA*VOL,0),4)/SUM(IF(AA<REF(AA,1),AA*VOL,0),4);
DD:=REF(100-(100/(1+CC)),1);
A1:=HHV(AA,15);
a2:=LLV(AA,15);
a3:=A1-a2;
a4:=EMA((AA-a2)/a3,2)*100;
b1:=HHV(AA,60);
b2:=LLV(AA,60);
b3:=b1-b2;
b4:=EMA((AA-b2)/b3,2)*100;
C1:=HHV(AA,240);
C2:=LLV(AA,240);
C3:=C1-C2;
C4:EMA((AA-C2)/C3,2)*100;
短期:a4,color00ff00;
中期:=b4,coloryellow;
长期:=C4,colorFF00FF;
STICKLINE(短期>90 AND 中期>70,86,94,6,0),COLOR00FF00;
STICKLINE(短期<5 AND 中期<30,0,8,6,0);
IF(FILTER(中期<REF(中期,1)AND 中期>90 AND BB<REF(BB,1),5),80,100),colorblue,Linethick2;
IF(FILTER(中期>REF(中期,1)AND 中期<5 AND C>REF(C,1),5),20,0),colorred,Linethick2;
D1:=中期>REF(中期,1)AND 短期>REF(短期,1)AND 长期>REF(长期,1)AND 长期<8 AND 中期<10 AND 短期<15;
D2:=CROSS(短期,中期)AND 中期<8;
D3:=CROSS(短期,长期)AND 长期<8 AND 中期<20;
强弱分界:50, Linethick,colorwhite;
警戒区:90,linethick1,colorwhite;
安全区:20,ColorFFFF00;
